var params = {};
for ( var k in DEFAULT_PARAMS ) params[k] = DEFAULT_PARAMS[k];

// -------------------------------------------------------------------------
// Utility
// -------------------------------------------------------------------------
function getAllImageIds() {
   var ids  = [];
   var wins = ImageWindow.windows;
   for ( var i = 0; i < wins.length; i++ )
      ids.push( wins[i].mainView.id );
   return ids;
}

function windowById( id ) {
   var wins = ImageWindow.windows;
   for ( var i = 0; i < wins.length; i++ )
      if ( wins[i].mainView.id == id )
         return wins[i];
   return null;
}

function closeWindowById( id ) {
   var w = windowById( id );
   if ( w ) w.forceClose();
}

function cloneWindow( srcId, newId ) {
   closeWindowById( newId );
   var srcWin = windowById( srcId );
   if ( !srcWin ) throw new Error( "Source image not found: " + srcId );
   var si = srcWin.mainView.image;
   var nw = new ImageWindow(
      si.width, si.height, si.numberOfChannels,
      si.bitsPerSample, si.isReal, si.isColor, newId
   );
   nw.mainView.beginProcess( UndoFlag.NoSwapFile );
   nw.mainView.image.assign( si );
   nw.mainView.endProcess();
   // Copy FITS keywords
   nw.keywords = srcWin.keywords;
   // Copy astrometric solution (stored in XISF metadata, not FITS keywords)
   try {
      if ( srcWin.hasAstrometricSolution )
         nw.copyAstrometricSolution( srcWin );
   } catch( e ) {
      console.warningln( "  Could not copy astrometric solution: " + e.message );
   }
   // Copy previews from source window to working clone
   // Also store rect of the selected ROI preview for MAS ROI coordinates
   try {
      var srcPreviews = srcWin.previews;
      for ( var pi = 0; pi < srcPreviews.length; pi++ ) {
         var pv   = srcPreviews[pi];
         var rect = srcWin.previewRect( pv );
         if ( rect && rect.width > 0 ) {
            nw.createPreview( rect, pv.id );
            console.writeln( "  Copied preview: " + pv.id );
            // Store rect for MAS ROI if this is the selected background preview
            if ( pv.id == params.roiPreviewId ) {
               params._roiRect = rect;
            }
         }
      }
   } catch( e ) {
      console.warningln( "  Could not copy preview(s): " + e.message );
   }
   nw.show();
   return nw;
}

function hasWCS( win ) {
   try {
      if ( typeof win.hasAstrometricSolution !== "undefined" )
         return win.hasAstrometricSolution;
      var kw = win.keywords;
      if ( kw )
         for ( var i = 0; i < kw.length; i++ )
            if ( kw[i].name == "CTYPE1" ) return true;
   } catch(e) {}
   return false;
}

// -------------------------------------------------------------------------
// Step 1: BlurXTerminator — correct only (no sharpening)
// -------------------------------------------------------------------------
function runBlurXCorrectOnly( view ) {
   console.writeln( "  BlurXTerminator (correct only): " + view.id );
   var bxt = new BlurXTerminator;
   bxt.auto_nonstellar_psf = true;
   bxt.correct_only        = true;
   bxt.sharpen_stars       = 0;
   bxt.sharpen_nonstellar  = 0;
   bxt.adjust_halos        = 0;
   bxt.executeOn( view );
}

// -------------------------------------------------------------------------
// Step 2: Gradient removal — tool selected by user
// -------------------------------------------------------------------------
function runGradientCorrection( view ) {
   console.writeln( "  GradientCorrection: " + view.id );
   var gc = new GradientCorrection;
   gc.automaticConvergence     = true;
   gc.generateGradientModel    = !!params.showGradientModel;
   gc.executeOn( view );
}

