function runMGC( view, srcId ) {
   console.writeln( "  MultiscaleGradientCorrection: " + view.id );
   var mgc = new MultiscaleGradientCorrection;
   // Leave referenceImageId empty — use MARS database only
   mgc.referenceImageId  = "";
   mgc.showGradientModel = !!params.showGradientModel;

   // Filter assignment depends on OSC vs mono
   if ( params.mgcIsOSC ) {
      mgc.grayMARSFilter  = "L";
      mgc.redMARSFilter   = "R";
      mgc.greenMARSFilter = "G";
      mgc.blueMARSFilter  = "B";
   } else {
      mgc.grayMARSFilter  = "L";
      mgc.redMARSFilter   = "SII";
      mgc.greenMARSFilter = "Ha";
      mgc.blueMARSFilter  = "OIII";
      console.writeln( "  MGC: mono narrowband mode (L/SII/Ha/OIII)." );
      console.writeln( "  Note: run SpectrophotometricFluxCalibration manually before using MGC with narrowband." );
   }

   // MARS database paths
   if ( params.mgcMarsPaths && params.mgcMarsPaths.trim() != "" ) {
      mgc.useMARSDatabase = true;
      var paths = params.mgcMarsPaths.split( ";" );
      var marsFiles = [];
      for ( var i = 0; i < paths.length; i++ ) {
         var p = paths[i].trim();
         if ( p != "" ) marsFiles.push( [ true, p ] );
      }
      if ( marsFiles.length > 0 ) mgc.marsDatabaseFiles = marsFiles;
   } else {
      // No MARS paths provided — MGC requires either MARS database or reference image
      // Without either, it will fail. Warn user.
      console.warningln( "  MGC: No MARS database paths specified. MGC requires MARS database files." );
      console.warningln( "  MGC: Add paths to .xmars files in the Gradient Removal section." );
      mgc.useMARSDatabase = false;
   }

   // Run SPFC first for OSC images
   if ( params.mgcIsOSC ) runSPFC( view );

   mgc.executeOn( view );
}

function runDBE( win ) {
   var view = win.mainView;
   var img  = view.image;
   console.writeln( "  DynamicBackgroundExtraction (perimeter boxes): " + view.id );

   // Dynamic radius based on image size — min 20, max 80px
   var radius = Math.round( Math.max( img.width, img.height ) / 100 );
   radius = Math.max( 20, Math.min( 80, radius ) );

   // Number of boxes per side scales with image size
   var boxesPerSide = Math.max( 4, Math.round( Math.max( img.width, img.height ) / 500 ) );
   var insetX = Math.round( img.width  * 0.05 );
   var insetY = Math.round( img.height * 0.05 );

   // Build samples in confirmed 12-value format:
   // [x, y, radius, symmetries, axialCount, isFixed, z0, w0, z1, w1, z2, w2]
   var samples = [];

   function addSample( cx, cy ) {
      cx = Math.max( radius, Math.min( img.width  - radius - 1, cx ) );
      cy = Math.max( radius, Math.min( img.height - radius - 1, cy ) );
      // Compute median brightness of this sample region for z/w values
      var rect = new Rect( cx - radius, cy - radius, cx + radius, cy + radius );
      img.selectedChannel = 0;
      var z0 = img.median( rect );
      img.resetSelections();
      var w0 = ( z0 > 0 ) ? 1.0 : 0.0;
      // For RGB images compute per channel, for grayscale duplicate
      var z1 = 0.0, w1 = 0.0, z2 = 0.0, w2 = 0.0;
      if ( img.numberOfChannels >= 3 ) {
         img.selectedChannel = 1;
         z1 = img.median( rect );
         img.resetSelections();
         w1 = ( z1 > 0 ) ? 1.0 : 0.0;
         img.selectedChannel = 2;
         z2 = img.median( rect );
         img.resetSelections();
         w2 = ( z2 > 0 ) ? 1.0 : 0.0;
      }
      samples.push( [ cx, cy, radius, 0, 6, 0, z0, w0, z1, w1, z2, w2 ] );
   }

   // Top and bottom edges
   for ( var i = 0; i < boxesPerSide; i++ ) {
      var x = insetX + Math.round( i * ( img.width - 2 * insetX ) / ( boxesPerSide - 1 ) );
      addSample( x, insetY );
      addSample( x, img.height - insetY );
   }
   // Left and right edges (skip corners already placed)
   for ( var j = 1; j < boxesPerSide - 1; j++ ) {
      var y = insetY + Math.round( j * ( img.height - 2 * insetY ) / ( boxesPerSide - 1 ) );
      addSample( insetX, y );
      addSample( img.width - insetX, y );
   }

   console.writeln( "  DBE: " + samples.length + " samples, radius=" + radius + "px" );

   var dbe = new DynamicBackgroundExtraction;
   dbe.samples              = samples;
   // Also populate data array with normalized coordinates
   var dataArr = [];
   for ( var d = 0; d < samples.length; d++ ) {
      var s = samples[d];
      dataArr.push( [
         s[0] / img.width,   // normalized x
         s[1] / img.height,  // normalized y
         s[6], s[7],         // z0, w0
         s[8], s[9],         // z1, w1
         s[10], s[11]        // z2, w2
      ] );
   }
   dbe.data                 = dataArr;
   dbe.defaultSampleRadius  = radius;
   dbe.targetCorrection     = 1;   // 1 = Subtract (confirmed from test: None=0, Subtract=1)
   dbe.smoothing            = 0.25;
   dbe.derivativeOrder      = 2;
   dbe.discardModel         = !!!params.showGradientModel;
   dbe.replaceTarget        = true;
   dbe.normalize            = false;
   dbe.imageWidth           = img.width;
   dbe.imageHeight          = img.height;
   dbe.executeOn( view );

   // Show gradient model if requested
   if ( params.showGradientModel ) {
      var modelId  = view.id + "_gradient";
      var modelWin = windowById( modelId );
      if ( !modelWin ) {
         // Try default DBE model naming
         var wins = ImageWindow.windows;
         for ( var k = 0; k < wins.length; k++ ) {
            if ( wins[k].mainView.id.indexOf( "background" ) >= 0 ||
                 wins[k].mainView.id.indexOf( "_model" ) >= 0 )
               wins[k].zoomToFit();
         }
      }
   }
}

function runGraXpert( view ) {
   console.writeln( "  GraXpert: " + view.id );
   var gx = new GraXpert;
   gx.backgroundExtraction = true;
   gx.smoothing            = params.graxpertSmoothing !== undefined ? params.graxpertSmoothing : 1.0;
   gx.correction           = "Subtraction";
   gx.createBackground     = !!params.showGradientModel;
   gx.denoising            = false;
   gx.strength             = params.graxpertStrength !== undefined ? params.graxpertStrength : 1.0;
   gx.batchSize            = 4;
   gx.disableGPU           = false;
   gx.replaceImage         = true;
   gx.showLogs             = false;
   gx.appPath              = "";
   gx.executeOn( view );
   Console.show(); // GraXpert is external — reopen console after it closes
}


// =========================================================================
// AutoDBE + Statistical Stretch — adapted from works by Franklin Marek / Seti Astro
// www.setiastro.com  |  CC BY-NC 4.0
// VeraLux HyperMetric Stretch — adapted from VeraLux v1.5.2 by Riccardo Paterniti
// info@veralux.space  |  GPL-3.0-or-later
// Because PixInsight scripts cannot directly call other third-party scripts,
// ProcessContainerPlus follows the same process as Seti Astro's AutoDBE
// rather than calling it externally.
// =========================================================================

function pcp_enumValue( obj, name, fallback ) {
   try { var v = obj[name]; if ( typeof v === "number" && isFinite(v) ) return v|0; } catch(e) {}
   return fallback;
}

var PCP_ABE_SUBTRACT = pcp_enumValue( AutomaticBackgroundExtractor, "Subtract", 0 );
var PCP_DBE_SUBTRACT = pcp_enumValue( DynamicBackgroundExtraction,  "Subtract", 0 );
var PCP_BN_RESCALE   = pcp_enumValue( BackgroundNeutralization, "RescaleAsNeeded", 0 );

function pcp_adbe_isOverlapping( r1, r2 ) {
   return !( r1.x1 < r2.x0 || r1.x0 > r2.x1 || r1.y1 < r2.y0 || r1.y0 > r2.y1 );
}
function pcp_adbe_windowSize( h )  { return Math.min( Math.round( h * 0.015 ), 30 ); }
function pcp_adbe_spacing( ws )    { return Math.ceil( ws * 0.5 ); }

function pcp_adbe_getAvgBrightness( img, x, y, ch ) {
   if ( ch == 1 ) return img.sample( x, y, 0 );
   return ( img.sample(x,y,0) + img.sample(x,y,1) + img.sample(x,y,2) ) / 3;
}

function pcp_adbe_getWindowStats( img, x, y, ws, ch, tol ) {
   var pv = []; for (var c=0;c<ch;c++) pv.push([]);
   for (var ox=0;ox<ws;ox++) for (var oy=0;oy<ws;oy++) for (var c=0;c<ch;c++)
      pv[c].push( img.sample(x+ox,y+oy,c) );
   var avg=[],sd=[];
   for (var c=0;c<ch;c++) {
      var mn=pv[c].reduce(function(a,b){return a+b;},0)/pv[c].length;
      var vr=pv[c].reduce(function(a,b){return a+Math.pow(b-mn,2);},0)/pv[c].length;
      var sg=Math.sqrt(vr);
      var fv=pv[c].filter(function(v){return Math.abs(v-mn)<=tol*sg;});
      var nm=fv.reduce(function(a,b){return a+b;},0)/fv.length;
      avg.push(nm); sd.push(Math.sqrt(fv.reduce(function(a,b){return a+Math.pow(b-nm,2);},0)/fv.length));
   }
   return { average:avg, stddev:sd };
}

function pcp_adbe_generateStartingPoints( iw, ih, ws, np, img, ch, excl ) {
   var pts=[],qw=Math.floor(iw/2),qh=Math.floor(ih/2),sr=100;
   var quads=[{sx:0,sy:0},{sx:qw,sy:0},{sx:0,sy:qh},{sx:qw,sy:qh}];
   var ppq=Math.ceil(np/quads.length);
   for (var qi=0;qi<quads.length;qi++) {
      var q=quads[qi],gb=[];
      for (var x=q.sx;x<q.sx+qw;x+=sr) for (var y=q.sy;y<q.sy+qh;y+=sr) {
         var reg={x0:x,y0:y,x1:x+sr,y1:y+sr};
         if (excl.some(function(e){return pcp_adbe_isOverlapping(reg,e);})) continue;
         var ab=0,cnt=0;
         for (var dx=0;dx<sr&&(x+dx)<iw;dx++) for (var dy=0;dy<sr&&(y+dy)<ih;dy++) {
            ab+=pcp_adbe_getAvgBrightness(img,x+dx,y+dy,ch); cnt++;
         }
         if (cnt>0) gb.push({x:x,y:y,avg:ab/cnt});
      }
      gb.sort(function(a,b){return a.avg-b.avg;});
      var fr=gb.slice(0,Math.floor(gb.length*2/3));
      fr.sort(function(){return Math.random()-0.5;});
      fr.slice(0,ppq).forEach(function(r){
         var px=Math.min(Math.floor(r.x+Math.random()*(sr-ws)),iw-ws);
         var py=Math.min(Math.floor(r.y+Math.random()*(sr-ws)),ih-ws);
         var pt={x0:px,y0:py,x1:px+ws,y1:py+ws};
         if (!excl.some(function(e){return pcp_adbe_isOverlapping(pt,e);})) pts.push({x:px,y:py});
      });
   }
   return pts.length>np?pts.slice(0,np):pts;
}

function pcp_adbe_findBestWindow( img, sx, sy, ws, sp, ch, tol ) {
   var bw={average:[],x:sx,y:sy};
   for (var c=0;c<ch;c++) bw.average.push(1e9);
   var cx=sx,cy=sy,improved=true;
   while (improved) {
      improved=false;
      for (var ox=-1;ox<=1;ox++) for (var oy=-1;oy<=1;oy++) {
         var nx=cx+ox*sp,ny=cy+oy*sp;
         if (nx>=0&&nx+ws<=img.width&&ny>=0&&ny+ws<=img.height) {
            var st=pcp_adbe_getWindowStats(img,nx,ny,ws,ch,tol);
            if (st.average.reduce(function(a,b){return a+b;},0)<bw.average.reduce(function(a,b){return a+b;},0)) {
               bw={average:st.average,x:nx,y:ny}; improved=true;
            }
         }
      }
      cx=bw.x; cy=bw.y;
   }
   return bw;
}

function pcp_adbe_calcMedian( vals ) {
   vals.sort(function(a,b){return a-b;}); var h=Math.floor(vals.length/2);
   return vals.length%2?vals[h]:(vals[h-1]+vals[h])/2;
}
function pcp_adbe_calcMAD( vals, med ) {
   return pcp_adbe_calcMedian( vals.map(function(v){return Math.abs(v-med);}) );
}
function pcp_adbe_noiseWeight( avg, med, mad ) {
   if (!Array.isArray(avg)) avg=[avg,avg,avg];
   if (!Array.isArray(med)) med=[med,med,med];
   if (!Array.isArray(mad)) mad=[mad,mad,mad];
   return avg.map(function(a,i){
      var m=med[i]||0.0001; var nf=1-(mad[i]/m);
      return Math.max(0,Math.min(1,nf));
   });
}
function pcp_adbe_spatialWeight( x, y, w, h ) {
   var cx=w/2,cy=h/2;
   var d=Math.sqrt(Math.pow(x-cx,2)+Math.pow(y-cy,2));
   var md=Math.sqrt(cx*cx+cy*cy);
   var nd=d/md; var cw=0.95+0.05*nd;
   var etx=w*0.1,ety=h*0.1;
   var ew=(x<etx||x>w-etx||y<ety||y>h-ety)?0.95:1.0;
   return cw*ew;
}

function pcp_getAllWindowIds() {
   var ids=[];
   for (var i=0;i<ImageWindow.windows.length;i++) ids.push(ImageWindow.windows[i].mainView.id);
   return ids;
}

function runAutoDBE( win ) {
   // Adapted from AutoDBE v1.6 by Franklin Marek / Seti Astro (CC BY-NC 4.0)
   var view = win.mainView;
   var img  = view.image;
   var ch   = img.numberOfChannels;
   var ws   = pcp_adbe_windowSize( img.height );
   var sp   = pcp_adbe_spacing( ws );
   var tol  = 2.0;
   var excl = [];

   // BN for color images
   if ( ch > 1 ) {
      var bn = new BackgroundNeutralization;
      bn.backgroundReferenceViewId = "";
      bn.backgroundLow    = 0.0;
      bn.backgroundHigh   = 0.12;
      bn.useROI           = false;
      bn.mode             = PCP_BN_RESCALE;
      bn.targetBackground = 0.001;
      bn.executeOn( view );
   }

   // ABE initial pass
   var winsBeforeABE = pcp_getAllWindowIds();
   var abe = new AutomaticBackgroundExtractor;
   abe.tolerance=1.0; abe.deviation=0.8; abe.unbalance=1.8;
   abe.minBoxFraction=0.05; abe.maxBackground=1.0; abe.minBackground=0.0;
   abe.useBrightnessLimits=false; abe.polyDegree=1; abe.boxSize=5;
   abe.boxSeparation=5; abe.abeDownsample=2.0; abe.writeSampleBoxes=false;
   abe.justTrySamples=false; abe.targetCorrection=PCP_ABE_SUBTRACT;
   abe.normalize=false; abe.discardModel=true; abe.replaceTarget=true;
   abe.correctedImageId=""; abe.executeOn( view );
   // Close any ABE model window that appeared
   var winsAfterABE = pcp_getAllWindowIds();
   for (var i=0;i<winsAfterABE.length;i++) {
      if (winsBeforeABE.indexOf(winsAfterABE[i])===-1) {
         var w=ImageWindow.windowById(winsAfterABE[i]); if(w&&!w.isNull) w.forceClose(); break;
      }
   }

   // Gradient descent sample placement
   var img_med = img.median();
   var img_std = img.stdDev();
   var threshold   = img_med + 0.3*img_std;
   var max_threshold = img_med + 0.15*img_std;

   var np=50;
   var edge_points=[
      {x:10,y:10},{x:img.width-ws-10,y:10},
      {x:10,y:img.height-ws-10},{x:img.width-ws-10,y:img.height-ws-10},
      {x:img.width/2-ws/2,y:10},{x:img.width/2-ws/2,y:img.height-ws-10},
      {x:10,y:img.height/2-ws/2},{x:img.width-ws-10,y:img.height/2-ws/2},
      {x:img.width/4-ws/2,y:10},{x:3*img.width/4-ws/2,y:10},
      {x:img.width/4-ws/2,y:img.height-ws-10},{x:3*img.width/4-ws/2,y:img.height-ws-10}
   ];
   var rand_pts = pcp_adbe_generateStartingPoints( img.width, img.height, ws, np, img, ch, excl );
   var all_pts  = edge_points.concat( rand_pts );

   var endPoints=[], bestWin=null, finalBrightnesses=[];

   function isInExcl(x,y) {
      for (var i=0;i<excl.length;i++) if(x>=excl[i].x0&&x<=excl[i].x1&&y>=excl[i].y0&&y<=excl[i].y1) return true;
      return false;
   }
   function runDescent( thresh, maxT, pts ) {
      for (var i=0;i<pts.length;i++) {
         var sp2=pts[i];
         if (isInExcl(sp2.x,sp2.y)) continue;
         var attempts=0;
         while (pcp_adbe_getWindowStats(img,sp2.x,sp2.y,ws,ch,tol).average.some(function(a){return a>=thresh;})&&attempts<10) {
            var rx=Math.floor(Math.random()*(img.width-ws));
            var ry=Math.floor(Math.random()*(img.height-ws));
            sp2={x:rx,y:ry}; attempts++;
         }
         var bw=pcp_adbe_findBestWindow(img,sp2.x,sp2.y,ws,sp,ch,tol);
         if (!bw.average.some(function(a){return a>maxT;})) {
            if (!bestWin||bw.average.reduce(function(a,b){return a+b;},0)<bestWin.average.reduce(function(a,b){return a+b;},0))
               bestWin=bw;
            var rb=bw.average.reduce(function(a,b){return a+b;},0)/ch;
            finalBrightnesses.push(rb);
            var med3=Array.isArray(img_med)?img_med:[img_med,img_med,img_med];
            var mad3=[0,0,0];
            endPoints.push({x:bw.x,y:bw.y,average:bw.average,mad:mad3,weights:pcp_adbe_noiseWeight(bw.average,med3,mad3)});
         }
      }
   }

   runDescent(threshold,max_threshold,all_pts);
   if (!bestWin) { threshold=2*img_med; max_threshold=img_med+2*img_std; runDescent(threshold,max_threshold,all_pts); }
   if (!bestWin) { console.warningln("  AutoDBE: all starting points rejected, falling back to DBE defaults."); return; }

   var med_b=pcp_adbe_calcMedian(finalBrightnesses.slice());
   var mad_b=pcp_adbe_calcMAD(finalBrightnesses.slice(),med_b);
   // Smoothing factor: matches Seti Astro AutoDBE v1.6 calculation
   var norm_mad = mad_b / ((img_med||0.0001) * 1.4826);
   var sf = Math.max(0.15, Math.min(0.5, 0.15 + (0.5-0.15) * (1 - norm_mad)));

   var med3=Array.isArray(img_med)?img_med:[img_med,img_med,img_med];
   while (endPoints.length<3) endPoints.push({x:Math.random()*(img.width-ws),y:Math.random()*(img.height-ws),average:med3.slice(),mad:[0,0,0]});

   var P = new DynamicBackgroundExtraction;
   P.data = endPoints.map(function(pt){
      var avg=pt.average.slice(),mad=pt.mad.slice();
      if(avg.length<3){avg=[avg[0],avg[0],avg[0]];} if(mad.length<3){mad=[mad[0]||0,mad[0]||0,mad[0]||0];}
      var nw=pcp_adbe_noiseWeight(avg,med3,mad);
      var sw=pcp_adbe_spatialWeight(pt.x,pt.y,img.width,img.height);
      var w0=nw[0]*sw,w1=(nw[1]||nw[0])*sw,w2=(nw[2]||nw[0])*sw;
      if(!isFinite(w0))w0=1; if(!isFinite(w1))w1=1; if(!isFinite(w2))w2=1;
      return [pt.x/img.width,pt.y/img.height,avg[0],w0,avg[1],w1,avg[2],w2];
   });
   P.samples = endPoints.map(function(pt){
      var avg=pt.average.slice(),mad=pt.mad.slice();
      if(avg.length<3){avg=[avg[0],avg[0],avg[0]];} if(mad.length<3){mad=[mad[0]||0,mad[0]||0,mad[0]||0];}
      var nw=pcp_adbe_noiseWeight(avg,med3,mad);
      var sw=pcp_adbe_spatialWeight(pt.x,pt.y,img.width,img.height);
      var w0=nw[0]*sw,w1=(nw[1]||nw[0])*sw,w2=(nw[2]||nw[0])*sw;
      if(!isFinite(w0))w0=1; if(!isFinite(w1))w1=1; if(!isFinite(w2))w2=1;
      return [pt.x,pt.y,ws/2,0,6,0,avg[0],w0,avg[1],w1,avg[2],w2];
   });
   P.numberOfChannels=3; P.derivativeOrder=2; P.smoothing=sf;
   P.ignoreWeights=false; P.modelId=""; P.modelWidth=0; P.modelHeight=0;
   P.downsample=2; P.targetCorrection=PCP_DBE_SUBTRACT; P.normalize=true;
   P.discardModel=!!!params.showGradientModel; P.replaceTarget=true; P.correctedImageId="";
   P.imageWidth=img.width; P.imageHeight=img.height;
   P.symmetryCenterX=0.5; P.symmetryCenterY=0.5;
   P.tolerance=tol; P.shadowsRelaxation=5.0; P.minSampleFraction=0.05;
   P.defaultSampleRadius=ws/2; P.samplesPerRow=10; P.minWeight=0.4;
   var winsBeforeDBE = pcp_getAllWindowIds();
   P.executeOn( view );

   // Close model window unless showGradientModel is enabled
   var winsAfterDBE = pcp_getAllWindowIds();
   for (var i=0;i<winsAfterDBE.length;i++) {
      if (winsBeforeDBE.indexOf(winsAfterDBE[i])===-1) {
         if (!params.showGradientModel) {
            var w=ImageWindow.windowById(winsAfterDBE[i]); if(w&&!w.isNull) w.forceClose();
         }
      }
   }
   console.writeln( "  AutoDBE complete: " + endPoints.length + " sample points used, smoothing=" + sf.toFixed(3) );
}

function runGradientStep( win, srcId ) {
   var view = win.mainView;
   switch ( params.gradientTool ) {
      case 1: runMGC( view, srcId );  break;
      case 2: runDBE( win );          break;
      case 3: runGraXpert( view );    break;
      case 4: runAutoDBE( win );      break;
      default: runGradientCorrection( view ); break;
   }
}

// -------------------------------------------------------------------------
// Step 3a: BackgroundNeutralization
// -------------------------------------------------------------------------
function runBackgroundNeutralization( view ) {
   console.writeln( "  BackgroundNeutralization: " + view.id );
   var bn = new BackgroundNeutralization;
   bn.backgroundLow             = 0.0;
   bn.backgroundHigh            = 0.1;
   bn.mode                      = BackgroundNeutralization.RescaleAsNeeded;
   bn.targetBackground          = 0.001;
   bn.backgroundReferenceViewId = "";
   if ( params.roiPreviewId != "" && params._roiRect ) {
      var r = params._roiRect;
      bn.useROI  = true;
      bn.roiX0   = r.x0;
      bn.roiY0   = r.y0;
      bn.roiX1   = r.x0 + r.width;
      bn.roiY1   = r.y0 + r.height;
   } else {
      bn.useROI  = false;
   }
   bn.executeOn( view );
}

// -------------------------------------------------------------------------
// Step 3b: SPCC — ideal QE curve, avg spiral galaxy
// -------------------------------------------------------------------------
function runSPCC( win ) {
   console.writeln( "  SPCC: " + win.mainView.id );
   if ( !hasWCS( win ) ) {
      console.warningln( "  SPCC skipped: no astrometric solution found on " +
                         win.mainView.id + ". Pre-solve your images before running." );
      return;
   }
   var spcc = new SpectrophotometricColorCalibration;
   var WHITE_REFS = [ "Average Spiral Galaxy", "Photon Flux" ];
   var QE_CURVES  = [
      "Ideal QE curve",
      "Sony IMX411/455/461/533/571",
      "Sony IMX183",
      "Sony IMX492",
      "Panasonic MN34230 (ASI1600MM)",
      "KAF-8300",
      "GSENSE400BSI",
      "GSENSE400FSI"
   ];
   var whiteRef = WHITE_REFS[ params.spccWhiteRef ] || "Average Spiral Galaxy";
   var qeCurve  = QE_CURVES[  params.spccQECurve  ] || "Ideal QE curve";
   spcc.narrowbandMode          = ( params.spccWhiteRef == 1 );
   spcc.whiteReferenceName      = whiteRef;
   spcc.deviceQECurveName       = qeCurve;
   spcc.narrowbandOptimizeStars = ( params.spccWhiteRef == 1 );
   spcc.applyCalibration        = true;
   spcc.generateGraphs          = false;
   spcc.generateStarMaps        = false;
   spcc.generateTextFiles       = false;
   // Apply background ROI from preview coordinates
   if ( params.roiPreviewId != "" && params._roiRect ) {
      var r = params._roiRect;
      spcc.backgroundReferenceViewId = "";
      spcc.backgroundUseROI          = true;
      spcc.backgroundROIX0           = r.x0;
      spcc.backgroundROIY0           = r.y0;
      spcc.backgroundROIX1           = r.x0 + r.width;
      spcc.backgroundROIY1           = r.y0 + r.height;
   }
   spcc.executeOn( win.mainView );
}

// -------------------------------------------------------------------------
// Step 4: BlurXTerminator — full sharpen pass
// -------------------------------------------------------------------------
function runBlurXSharpen( view ) {
   console.writeln( "  BlurXTerminator (sharpen): " + view.id );
   var bxt = new BlurXTerminator;
   bxt.auto_nonstellar_psf = true;
   bxt.correct_only        = false;
   bxt.sharpen_stars       = params.bxtSharpenStars;
   bxt.sharpen_nonstellar  = params.bxtSharpenNonstellar;
   bxt.adjust_halos        = params.bxtAdjustHalos;
   bxt.executeOn( view );
}

// -------------------------------------------------------------------------
// Step 5a: HT auto-stretch — compute fresh STF from clone, apply as HT
// -------------------------------------------------------------------------

// =========================================================================
// Statistical Stretch — adapted from Statistical Stretch v2.3
// Author: Franklin Marek / Seti Astro (www.setiastro.com)
// License: CC BY-NC 4.0 (http://creativecommons.org/licenses/by-nc/4.0/)
// =========================================================================
function runStatisticalStretch( view ) {
   console.writeln( "  Statistical Stretch: " + view.id );
   var img = view.image;
   var isColor = img.numberOfChannels >= 3;
   var bp = params.statStretchBlackpointSigma;
   var tm = params.statStretchTargetMedian;
   var P = new ProcessContainer;

   var P1 = new PixelMath;
   if ( isColor ) {
      P1.expression =
         "cr=0.2126;cg=0.7152;cb=0.0722;\n" +
         "Med=cr*med($T[0])+cg*med($T[1])+cb*med($T[2]);\n" +
         "Sig=1.4826*(cr*MAD($T[0])+cg*MAD($T[1])+cb*MAD($T[2]));\n" +
         "MinC=min(min($T[0]),min($T[1]),min($T[2]));\n" +
         "BPraw=Med-" + bp.toFixed(4) + "*Sig;\n" +
         "BP=iif(BPraw<MinC,MinC,BPraw);\n" +
         "($T-BP)/(1-BP);";
      P1.symbols = "cr,cg,cb,Med,Sig,MinC,BPraw,BP";
   } else {
      P1.expression =
         "Med=med($T);\n" +
         "Sig=1.4826*MAD($T);\n" +
         "BPraw=Med-" + bp.toFixed(4) + "*Sig;\n" +
         "BP=iif(BPraw<min($T),min($T),BPraw);\n" +
         "($T-BP)/(1-BP);";
      P1.symbols = "Med,Sig,BPraw,BP";
   }
   P1.useSingleExpression=true; P1.generateOutput=true;
   P1.rescale=false; P1.truncate=true;
   P1.createNewImage=false; P1.showNewImage=false;
   P.add( P1 );

   var P2 = new PixelMath;
   if ( isColor ) {
      P2.expression = "MedianColor=avg(med($T[0]),med($T[1]),med($T[2]));\n" +
         "((MedianColor-1)*" + tm.toFixed(4) + "*$T)/(MedianColor*(" + tm.toFixed(4) + "+$T-1)-" + tm.toFixed(4) + "*$T);";
      P2.symbols = "MedianColor";
   } else {
      P2.expression = "((med($T)-1)*" + tm.toFixed(4) + "*$T)/(med($T)*(" + tm.toFixed(4) + "+$T-1)-" + tm.toFixed(4) + "*$T);";
   }
   P2.useSingleExpression=true; P2.generateOutput=true;
   P2.rescale=false; P2.truncate=false;
   P2.createNewImage=false; P2.showNewImage=false;
   P.add( P2 );

   var P3 = new PixelMath;
   P3.expression = "$T;"; P3.useSingleExpression=true;
   P3.generateOutput=true; P3.rescale=false; P3.truncate=true;
   P3.createNewImage=false; P3.showNewImage=false;
   P.add( P3 );

   P.executeOn( view );
}


// =========================================================================
// VeraLux HyperMetric Stretch — adapted from VeraLux v1.5.2
// Original: Riccardo Paterniti (info@veralux.space), GPL-3.0-or-later
