function runVeraLux( view ) {
   console.writeln( "  VeraLux HyperMetric Stretch: " + view.id );
   var img   = view.image;
   var nc    = img.numberOfChannels;
   var isRGB = nc >= 3;
   var weights = [0.2126, 0.7152, 0.0722];
   var logD  = params.veraluxLogD;
   var bVal  = params.veraluxProtectB;
   var targetBg = params.veraluxTargetBg;

   var work = new Image( img.width, img.height, nc,
      isRGB ? ColorSpace.RGB : ColorSpace.Gray, 32, PixelSampleType.Float );
   work.assign( img );

   // Adaptive anchor
   function calcAnchor( image ) {
      var w=image.width,h=image.height,n=w*h;
      var stride=Math.max(1,Math.floor(n/2000000));
      var nBins=65536,hist=new Float64Array(nBins);
      if(isRGB){
         var Ir=new ImageIterator(image,0),Ig=new ImageIterator(image,1),Ib=new ImageIterator(image,2);
         var wr=weights[0],wg=weights[1],wb=weights[2];
         for(var i=0;i<n;i+=stride){var x=i%w,y=(i/w)|0;var v=wr*Ir[y][x]+wg*Ig[y][x]+wb*Ib[y][x];var bin=(v*(nBins-1))|0;if(bin>=0&&bin<nBins)hist[bin]++;}
      } else {
         var Im=new ImageIterator(image,0);
         for(var i=0;i<n;i+=stride){var x=i%w,y=(i/w)|0;var v=Im[y][x];var bin=(v*(nBins-1))|0;if(bin>=0&&bin<nBins)hist[bin]++;}
      }
      var smoothed=new Float64Array(nBins),win=50,sum=0;
      for(var k=0;k<win&&k<nBins;k++)sum+=hist[k];
      for(var k=0;k<nBins;k++){if(k+win<nBins)sum+=hist[k+win];if(k-win-1>=0)sum-=hist[k-win-1];var cnt=Math.min(k+win,nBins-1)-Math.max(k-win,0)+1;smoothed[k]=sum/cnt;}
      var peakIdx=100,peakVal=0;
      for(var k=100;k<nBins;k++)if(smoothed[k]>peakVal){peakVal=smoothed[k];peakIdx=k;}
      var target=peakVal*0.06,anchorIdx=-1;
      for(var k=peakIdx-1;k>=0;k--)if(smoothed[k]<target){anchorIdx=k;break;}
      if(anchorIdx<0){image.selectedChannel=0;var m=image.median();image.resetSelections();return Math.max(0,m);}
      return Math.max(0,anchorIdx/(nBins-1));
   }

   var anchor=calcAnchor(work);
   var D=Math.pow(10,logD);
   var t2=Math.asinh(bVal);
   var norm=Math.asinh(D+bVal)-t2;
   if(Math.abs(norm)<1e-12)norm=1e-6;

   var lumStr=new Image(img.width,img.height,1,ColorSpace.Gray,32,PixelSampleType.Float);
   var IL=new ImageIterator(lumStr,0);
   if(isRGB){
      var Ir=new ImageIterator(work,0),Ig=new ImageIterator(work,1),Ib=new ImageIterator(work,2);
      var wr=weights[0],wg=weights[1],wb=weights[2];
      for(var y=0;y<img.height;y++){var ir=Ir[y],ig=Ig[y],ib=Ib[y],il=IL[y];for(var x=0;x<img.width;x++){var r=ir[x]-anchor;if(r<0)r=0;var g=ig[x]-anchor;if(g<0)g=0;var bv=ib[x]-anchor;if(bv<0)bv=0;var L=wr*r+wg*g+wb*bv;var s=(Math.asinh(D*L+bVal)-t2)/norm;il[x]=s<0?0:s>1?1:s;}}
   } else {
      var Im=new ImageIterator(work,0);
      for(var y=0;y<img.height;y++){var im=Im[y],il=IL[y];for(var x=0;x<img.width;x++){var v=im[x]-anchor;if(v<0)v=0;var s=(Math.asinh(D*v+bVal)-t2)/norm;il[x]=s<0?0:s>1?1:s;}}
   }

   var convPow=3.5,pedestal=0.005,oneMP=1-pedestal,eps=1e-9;
   var result=new Image(img.width,img.height,nc,isRGB?ColorSpace.RGB:ColorSpace.Gray,32,PixelSampleType.Float);
   if(isRGB){
      var Ir=new ImageIterator(work,0),Ig=new ImageIterator(work,1),Ib=new ImageIterator(work,2);
      var Or=new ImageIterator(result,0),Og=new ImageIterator(result,1),Ob=new ImageIterator(result,2);
      var wr=weights[0],wg=weights[1],wb=weights[2];
      for(var y=0;y<img.height;y++){var ir=Ir[y],ig=Ig[y],ib=Ib[y],il=IL[y],or_=Or[y],og=Og[y],ob=Ob[y];for(var x=0;x<img.width;x++){var r=ir[x]-anchor;if(r<0)r=0;var g=ig[x]-anchor;if(g<0)g=0;var bv=ib[x]-anchor;if(bv<0)bv=0;var Lv=wr*r+wg*g+wb*bv;var Ls=il[x];var k=Math.pow(Ls,convPow);var omk=1-k;var rF=Ls*((r/(Lv+eps))*omk+k);var gF=Ls*((g/(Lv+eps))*omk+k);var bF=Ls*((bv/(Lv+eps))*omk+k);or_[x]=rF*oneMP+pedestal;og[x]=gF*oneMP+pedestal;ob[x]=bF*oneMP+pedestal;}}
   } else {
      var Or=new ImageIterator(result,0);
      for(var y=0;y<img.height;y++){var il=IL[y],or_=Or[y];for(var x=0;x<img.width;x++){or_[x]=il[x]*oneMP+pedestal;}}
   }
   work.free(); lumStr.free();

   // Adaptive output scaling with Smart-Max
   function sampleLuma(image){
      var w=image.width,h=image.height,n=w*h,stride=Math.max(1,Math.floor(n/500000)),arr=[];
      if(isRGB){var Ir=new ImageIterator(image,0),Ig=new ImageIterator(image,1),Ib=new ImageIterator(image,2),wr=weights[0],wg=weights[1],wb=weights[2];for(var i=0;i<n;i+=stride){var x=i%w,y=(i/w)|0;arr.push(wr*Ir[y][x]+wg*Ig[y][x]+wb*Ib[y][x]);}}
      else{var Im=new ImageIterator(image,0);for(var i=0;i<n;i+=stride){var x=i%w,y=(i/w)|0;arr.push(Im[y][x]);}}
      arr.sort(function(a,b){return a-b;}); return arr;
   }
   function pct(sorted,p){var n=sorted.length;if(n===0)return 0;var idx=(p/100)*(n-1);var lo=Math.floor(idx),hi=Math.ceil(idx);if(hi>=n)return sorted[n-1];return sorted[lo]*(1-(idx-lo))+sorted[hi]*(idx-lo);}
   var lumas=sampleLuma(result);
   var median=pct(lumas,50),mean=0;
   for(var i=0;i<lumas.length;i++)mean+=lumas[i]; mean/=lumas.length;
   var std=0; for(var i=0;i<lumas.length;i++){var dv=lumas[i]-mean;std+=dv*dv;} std=Math.sqrt(std/lumas.length);
   var globalFloor=Math.max(lumas[0],median-2.7*std);
   var PEDESTAL=0.001;
   var absMax=-Infinity,xMax=0,yMax=0;
   if(isRGB){var Ir=new ImageIterator(result,0),Ig=new ImageIterator(result,1),Ib=new ImageIterator(result,2),wr=weights[0],wg=weights[1],wb=weights[2];for(var y=0;y<result.height;y++){var ir=Ir[y],ig=Ig[y],ib=Ib[y];for(var x=0;x<result.width;x++){var Lv=wr*ir[x]+wg*ig[x]+wb*ib[x];if(Lv>absMax){absMax=Lv;xMax=x;yMax=y;}}}}
   else{var Im=new ImageIterator(result,0);for(var y=0;y<result.height;y++){var im=Im[y];for(var x=0;x<result.width;x++)if(im[x]>absMax){absMax=im[x];xMax=x;yMax=y;}}}
   var validPhysical=true;
   if(absMax>0.001){
      var y0v=Math.max(0,yMax-1),y1v=Math.min(result.height,yMax+2),x0v=Math.max(0,xMax-1),x1v=Math.min(result.width,xMax+2);
      var maxNeighbor=-Infinity,anyNeighbor=false;
      if(isRGB){var Ir2=new ImageIterator(result,0),Ig2=new ImageIterator(result,1),Ib2=new ImageIterator(result,2),wr2=weights[0],wg2=weights[1],wb2=weights[2];for(var y=y0v;y<y1v;y++){var ir=Ir2[y],ig=Ig2[y],ib=Ib2[y];for(var x=x0v;x<x1v;x++){var Lv=wr2*ir[x]+wg2*ig[x]+wb2*ib[x];if(Lv<absMax){anyNeighbor=true;if(Lv>maxNeighbor)maxNeighbor=Lv;}}}}
      else{var Im2=new ImageIterator(result,0);for(var y=y0v;y<y1v;y++){var im2=Im2[y];for(var x=x0v;x<x1v;x++){var Lv=im2[x];if(Lv<absMax){anyNeighbor=true;if(Lv>maxNeighbor)maxNeighbor=Lv;}}}}
      if(anyNeighbor&&maxNeighbor<absMax*0.20)validPhysical=false;
   }
   var softCeil;
   if(isRGB){var cs0=[],cs1=[],cs2=[],str2=Math.max(1,Math.floor(result.width*result.height/500000));var Ir3=new ImageIterator(result,0),Ig3=new ImageIterator(result,1),Ib3=new ImageIterator(result,2);for(var y=0;y<result.height;y++){var ir=Ir3[y],ig=Ig3[y],ib=Ib3[y];for(var x=0;x<result.width;x+=str2){cs0.push(ir[x]);cs1.push(ig[x]);cs2.push(ib[x]);}}cs0.sort(function(a,b){return a-b;});cs1.sort(function(a,b){return a-b;});cs2.sort(function(a,b){return a-b;});softCeil=Math.max(pct(cs0,99),pct(cs1,99),pct(cs2,99));}
   else{var cs=[],Im3=new ImageIterator(result,0);for(var y=0;y<result.height;y++){var im3=Im3[y];for(var x=0;x<result.width;x++)cs.push(im3[x]);}cs.sort(function(a,b){return a-b;});softCeil=pct(cs,99);}
   if(softCeil<=globalFloor)softCeil=globalFloor+1e-6;
   if(absMax<=softCeil)absMax=softCeil+1e-6;
   var scaleC=(0.98-PEDESTAL)/(softCeil-globalFloor+1e-9);
   var finalScale=validPhysical?Math.min(scaleC,(1.0-PEDESTAL)/(absMax-globalFloor+1e-9)):scaleC;
   for(var c=0;c<nc;c++){var I=new ImageIterator(result,c);for(var y=0;y<result.height;y++){var row=I[y];for(var x=0;x<result.width;x++){var v=(row[x]-globalFloor)*finalScale+PEDESTAL;row[x]=v<0?0:v>1?1:v;}}}
   for(var c=0;c<nc;c++){var I=new ImageIterator(result,c);for(var y=0;y<result.height;y++){var row=I[y];for(var x=0;x<result.width;x++){var v=row[x];if(v>0.98){var t=(v-0.98)/0.02;if(t>1)t=1;row[x]=0.98+0.02*(1-Math.pow(1-t,2));}}}}
   var lumas2=sampleLuma(result),curBg=pct(lumas2,50);
   if(curBg>0&&curBg<1&&Math.abs(curBg-targetBg)>1e-3){var m=(curBg*(targetBg-1))/(curBg*(2*targetBg-1)-targetBg);for(var c=0;c<nc;c++){var I=new ImageIterator(result,c);for(var y=0;y<result.height;y++){var row=I[y];for(var x=0;x<result.width;x++){var v=row[x];if(v<=0)row[x]=0;else if(v>=1)row[x]=1;else{var num=(m-1)*v;var den=(2*m-1)*v-m;if(Math.abs(den)<1e-12)row[x]=v;else{var r=num/den;row[x]=r<0?0:r>1?1:r;}}}}}}

   view.beginProcess(UndoFlag.NoSwapFile);
   view.image.assign(result);
   view.endProcess();
   result.free();
}

function runHTAutoStretch( view ) {
   console.writeln( "  HistogramTransformation (auto-stretch): " + view.id );
   var img      = view.image;
   var nChannels = img.numberOfChannels;
   var B  = 0.25;    // target background
   var C  = -2.8;    // shadows clipping in sigma units

   function computeHTRow( channel ) {
      img.selectedChannel = channel;
      var median = img.median();
      var mad    = img.MAD();
      img.resetSelections();
      mad = mad > 0 ? mad * 1.4826 : 1e-10;
      var shadows  = Math.max( 0, median + C * mad );
      var range    = median - shadows;
      var midtones = range > 0
         ? ( B * range ) / ( ( 2*B - 1 ) * range - B )
         : 0.5;
      midtones = Math.max( 0.001, Math.min( 0.999, midtones ) );
      return [ shadows, midtones, 1.0, 0.0, 1.0 ];
   }

   var identity = [ 0.0, 0.5, 1.0, 0.0, 1.0 ];
   var ht = new HistogramTransformation;

   if ( nChannels == 1 ) {
      var k = computeHTRow( 0 );
      ht.H = [
         identity,
         identity,
         identity,
         k,
         identity
      ];
   } else {
      var r = computeHTRow( 0 );
      var g = computeHTRow( 1 );
      var b = computeHTRow( 2 );
      ht.H = [
         r,
         g,
         b,
         identity,
         identity
      ];
   }
   ht.executeOn( view );
}

// -------------------------------------------------------------------------
// Step 5b: MultiscaleAdaptiveStretch
// -------------------------------------------------------------------------

// IterativeStretch — inline for PCP pipeline
function runIterativeStretch( view ) {
   console.writeln( "  IterativeStretch: " + view.id );
   var img     = view.image;
   var isColor = img.numberOfChannels >= 3;
   var nPasses = Math.round( params.isNumPasses ) || 3;
   var tgtBg   = params.isTargetBg   || 0.20;
   var spRange = params.isSpRange    || 0.50;
   var sigmaC  = params.isShadowsSigma != null ? params.isShadowsSigma : -2.80;

   function _bpFromSigma( im, C ) {
      var nc = im.numberOfChannels; var minBP = 1.0;
      for ( var ch=0; ch<Math.min(nc,3); ch++ ) {
         im.selectedChannel = ch;
         var med=im.median(); var mad=im.MAD();
         im.resetSelections();
         mad=(mad>0)?mad*1.4826:1e-10;
         var bp=Math.max(0,med+C*mad);
         if(bp<minBP)minBP=bp;
      }
      return minBP;
   }
   function _passIntensity(pass,total){var t={1:[4],2:[8,1],3:[8,3,1],4:[8,4,2,0],5:[8,5,2,1,0]};var tbl=t[total]||t[3];return(pass<tbl.length)?tbl[pass]:0;}
   function _midtones(sp,tBg){var d=(2*tBg-1)*sp-tBg;return Math.abs(d)<1e-10?0.5:Math.max(0.001,Math.min(0.999,((tBg-1)*sp)/d));}
   function _applyIntensity(mid,b){if(b<=0)return mid;return Math.max(0.001,Math.min(0.999,mid/(1.0+b*(1.0-mid))));}

   var firstTgt = tgtBg + 0.30;
   for ( var pass=0; pass<nPasses; pass++ ) {
      var nc2 = img.numberOfChannels;
      img.selectedChannel = 0; var med=img.median(); var mad=img.MAD(); img.resetSelections();
      mad=(mad>0)?mad*1.4826:1e-10;
      var p005=Math.max(0,med-2.5*mad); var p001=Math.max(0,med-3.0*mad); var p50=med; var p90=Math.min(1,med+spRange*(1.0-med));
      var bp=_bpFromSigma(img,sigmaC);
      var shoulder=p005+0.35*(p50-p005);
      var base=(pass===0)?shoulder:p001+mad*0.5;
      var hi=p50+spRange*(p90-p50);
      var t2=pass/Math.max(1,nPasses-1);
      var sp=base+t2*(hi-base);
      var tBg=firstTgt-t2*(firstTgt-tgtBg);
      var b=_passIntensity(pass,nPasses);
      var range=1.0-bp; if(range<1e-10)range=1.0;
      var spNorm=Math.max(0,Math.min(1,(sp-bp)/range));
      var mid=_applyIntensity(_midtones(spNorm,tBg),b);
      var ht=new HistogramTransformation;
      var id=[0,0.5,1.0,0.0,1.0]; var row=[bp,mid,1.0,0.0,1.0];
      if(!isColor)ht.H=[id,id,id,row,id];else ht.H=[row,row,row,id,id];
      ht.executeOn(view,false);
      console.writeln("    pass "+(pass+1)+"/"+nPasses+"  BP="+bp.toFixed(5)+"  SP="+sp.toFixed(5)+"  b="+b);
   }
}

function runMAS( view ) {
   console.writeln( "  MultiscaleAdaptiveStretch: " + view.id );
   var mas = new MultiscaleAdaptiveStretch;
   mas.targetBackground          = params.masTargetBackground;
   mas.aggressiveness            = params.masAggressiveness;
   mas.dynamicRangeCompression   = params.masDynRangeComp;
   mas.contrastRecovery          = true;
   mas.scaleSeparation           = 1024;
   mas.contrastRecoveryIntensity = 1.0;
   mas.colorSaturation           = true;
   mas.colorSaturationAmount     = params.masColorSaturation;
   mas.colorSaturationBoost      = 0.50;
   // Apply background ROI from preview if available
   if ( params.roiPreviewId != "" && params._roiRect ) {
      var r = params._roiRect;
      mas.backgroundROIEnabled  = true;
      mas.backgroundROIX0       = r.x0;
      mas.backgroundROIY0       = r.y0;
      mas.backgroundROIWidth    = r.width;
      mas.backgroundROIHeight   = r.height;
      console.writeln( "  MAS background ROI: [" + r.x0 + "," + r.y0 + "," + r.width + "x" + r.height + "]" );
   }
   mas.executeOn( view );
}

// -------------------------------------------------------------------------
// Step 6: StarXTerminator — unscreen on, optional large overlap
// -------------------------------------------------------------------------
function runStarX( win, useUnscreen, saveStars ) {
   var view = win.mainView;
   console.writeln( "  StarXTerminator: " + view.id );
   var sxt = new StarXTerminator;
   sxt.stars    = !!saveStars;
   sxt.unscreen = ( useUnscreen !== false );  // default true, false for linear
   if ( params.starxLargeOverlap ) sxt.overlap = 0.5;
   sxt.executeOn( view );
   if ( saveStars ) {
      console.writeln( "  Stars image generated by StarXTerminator." );
      var starsId  = win.mainView.id + "_stars";
      var starsWin = windowById( starsId );
      if ( starsWin ) { starsWin.show(); starsWin.zoom = -2; }
   }
}

function runStretchedStarClone( win ) {
   console.writeln( "  Creating stretched star clone..." );
   var cloneId  = win.mainView.id + "_starclone";
   var cloneWin = cloneWindow( win.mainView.id, cloneId );
   // Stretch the clone with MAS at star-specific aggressiveness
   var mas = new MultiscaleAdaptiveStretch;
   mas.targetBackground        = 0.15;
   mas.aggressiveness          = params.starxStretchAgg;
   mas.dynamicRangeCompression = 0.40;
   mas.contrastRecovery        = true;
   mas.scaleSeparation         = 1024;
   mas.contrastRecoveryIntensity = 1.0;
   mas.colorSaturation         = true;
   mas.colorSaturationAmount   = ( params.starxCloneColorSat !== undefined ) ? params.starxCloneColorSat : 0.75;
   mas.colorSaturationBoost    = 0.50;
   mas.executeOn( cloneWin.mainView );
   // Extract stars from stretched clone
   var sxt = new StarXTerminator;
   sxt.stars    = true;
   sxt.unscreen = true;
   if ( params.starxLargeOverlap ) sxt.overlap = 0.5;
   sxt.executeOn( cloneWin.mainView );
   // The star image from clone is named cloneId_stars
   // Rename it to finalId_stars replacing default star image
   var cloneStarsId  = cloneId + "_stars";
   var cloneStarsWin = windowById( cloneStarsId );
   if ( cloneStarsWin ) {
      cloneStarsWin.mainView.id = win.mainView.id + "_stars";
      cloneStarsWin.show();
      cloneStarsWin.zoom = -2;
   }
   // Close the clone
   closeWindowById( cloneId );
   console.writeln( "  Stretched star image generated." );
}

function runStarRecombine( win ) {
   console.writeln( "  Star recombination: " + win.mainView.id );
   var starsId  = win.mainView.id + "_stars";
   var starsWin = windowById( starsId );
   if ( !starsWin ) {
      console.warningln( "  Star recombination skipped: no star image found (" + starsId + ")" );
      return;
   }
   var pm = new PixelMath;
   pm.expression  = "~(~" + win.mainView.id + "*~" + starsId + ")";
   pm.useSingleExpression = true;
   pm.createNewImage      = false;
   pm.executeOn( win.mainView );
   console.writeln( "  Stars recombined via screen blend." );
}

// -------------------------------------------------------------------------
// Step 7: NoiseXTerminator
// -------------------------------------------------------------------------
function runNoiseX( view ) {
   console.writeln( "  NoiseXTerminator: " + view.id );
   var nxt = new NoiseXTerminator;
   var colorSep = !!params.noisexColorSep;
   var freqSep  = !!params.noisexFreqSep;

   if ( colorSep && freqSep ) {
      // All four channels independent
      nxt.denoise           = params.noisexDenoiseHFI;
      nxt.denoise_color     = params.noisexDenoiseHFC;
      nxt.denoise_lf        = params.noisexDenoiseLFI;
      nxt.denoise_lf_color  = params.noisexDenoiseLFC;
   } else if ( colorSep ) {
      // Intensity vs color, no freq split
      nxt.denoise           = params.noisexDenoiseHFI;
      nxt.denoise_color     = params.noisexDenoiseHFC;
      nxt.denoise_lf        = params.noisexDenoiseHFI;
      nxt.denoise_lf_color  = params.noisexDenoiseHFC;
   } else if ( freqSep ) {
      // HF vs LF, no color split
      nxt.denoise           = params.noisexDenoiseHFI;
      nxt.denoise_color     = params.noisexDenoiseHFI;
      nxt.denoise_lf        = params.noisexDenoiseLFI;
      nxt.denoise_lf_color  = params.noisexDenoiseLFI;
   } else {
      // Single denoise value
      nxt.denoise           = params.noisexDenoise;
      nxt.denoise_color     = params.noisexDenoise;
      nxt.denoise_lf        = params.noisexDenoise;
      nxt.denoise_lf_color  = params.noisexDenoise;
   }
   nxt.enable_color_separation     = colorSep;
   nxt.enable_frequency_separation = freqSep;
   nxt.frequency_scale             = params.noisexScale;
   nxt.iterations                  = params.noisexIterations;
   nxt.executeOn( view );
}

// -------------------------------------------------------------------------
// Process a single image through the full pipeline
// -------------------------------------------------------------------------
function formatElapsed( ms ) {
   var s = ms / 1000;
   if ( s < 60 ) return s.toFixed(1) + "s";
   var m = Math.floor( s / 60 );
   return m + "m " + (s - m*60).toFixed(0) + "s";
}

function processImage( srcId ) {
   var workId = "_pcp_work";
   closeWindowById( workId );

   console.writeln( "" );
   console.writeln( "  Processing: " + srcId );
   console.writeln( "  ----------------------------------------" );

   var workWin = cloneWindow( srcId, workId );
   var view    = workWin.mainView;
   var pipelineStart = Date.now();
   var timingLog = { blurxCorrect:"--", gradient:"--", bn:"--", spcc:"--", blurxSharpen:"--", stretch:"--", starClone:"--", starMain:"--", starx:"--", noisex:"--" };

   try {
      var t0;
      if ( params.enableBlurXCorrect ) {
         t0 = Date.now(); runBlurXCorrectOnly( view );
         timingLog.blurxCorrect = formatElapsed( Date.now()-t0 );
         console.writeln( "  BlurX correct: " + timingLog.blurxCorrect );
      }
      if ( params.enableGradientCorrect ) {
         t0 = Date.now(); runGradientStep( workWin, srcId );
         timingLog.gradient = formatElapsed( Date.now()-t0 );
         console.writeln( "  Gradient removal: " + timingLog.gradient );
      }
      if ( params.enableBackgroundNeutralization ) {
         t0 = Date.now(); runBackgroundNeutralization( view );
         timingLog.bn = formatElapsed( Date.now()-t0 );
         console.writeln( "  BackgroundNeutralization: " + timingLog.bn );
      }
      if ( params.enableSPCC ) {
         t0 = Date.now(); runSPCC( workWin );
         timingLog.spcc = formatElapsed( Date.now()-t0 );
         console.writeln( "  SPCC: " + timingLog.spcc );
      }
      if ( params.enableBlurXSharpen ) {
         t0 = Date.now(); runBlurXSharpen( view );
         timingLog.blurxSharpen = formatElapsed( Date.now()-t0 );
         console.writeln( "  BlurX sharpen: " + timingLog.blurxSharpen );
      }

      // -----------------------------------------------------------------------
      // Star removal scenarios — driven by starxStarMode
      //   0 = None (no star image, just remove stars from main)
      //   1 = Linear star image (extract linear stars before stretch)
      //   2 = Stretched star image (clone, MAS stretch clone, extract from clone)
      // -----------------------------------------------------------------------
      var finalId   = srcId + params.outputSuffix;
      var starMode  = params.enableStarX ? ( params.starxStarMode || 0 ) : 0;

      if ( starMode == 2 ) {
         // STRETCHED STAR IMAGE: clone pre-stretch, MAS the clone, StarX the clone
         // Then stretch main, StarX main with no star output
         console.writeln( "  Star mode: Stretched star image" );
         t0 = Date.now();
         var starCloneId  = workId + "_starclone";
         var starCloneWin = cloneWindow( workId, starCloneId );
         // MAS stretch the clone
         var masClone = new MultiscaleAdaptiveStretch;
         masClone.targetBackground          = 0.15;
         masClone.aggressiveness            = params.starxStretchAgg;
         masClone.dynamicRangeCompression   = 0.40;
         masClone.contrastRecovery          = true;
         masClone.scaleSeparation           = 1024;
         masClone.contrastRecoveryIntensity = 1.0;
         masClone.colorSaturation           = true;
         masClone.colorSaturationAmount     = ( params.starxCloneColorSat !== undefined ) ? params.starxCloneColorSat : 0.75;
         masClone.colorSaturationBoost      = 0.50;
         masClone.executeOn( starCloneWin.mainView );
         // StarX on stretched clone — unscreen, save star image
         var sxtClone = new StarXTerminator;
         sxtClone.stars    = true;
         sxtClone.unscreen = true;
         if ( params.starxLargeOverlap ) sxtClone.overlap = 0.5;
         sxtClone.executeOn( starCloneWin.mainView );
         // Rename star image to final name
         var cloneStarsId  = starCloneId + "_stars";
         var cloneStarsWin = windowById( cloneStarsId );
         if ( cloneStarsWin ) {
            cloneStarsWin.mainView.id = finalId + "_stars";
            cloneStarsWin.show();
            cloneStarsWin.zoom = -2;
         }
         closeWindowById( starCloneId );
         timingLog.starClone = formatElapsed( Date.now()-t0 );
         console.writeln( "  Star clone + StarX: " + timingLog.starClone );
         // Stretch main image (if stretch enabled)
         if ( params.enableMAS ) {
            t0 = Date.now();
            if      ( params.stretchTool == 1 ) runHTAutoStretch( workWin.mainView );
            else if ( params.stretchTool == 2 ) runStatisticalStretch( workWin.mainView );
            else if ( params.stretchTool == 3 ) runVeraLux( workWin.mainView );
            else if ( params.stretchTool == 4 ) runIterativeStretch( workWin.mainView );
            else                                runMAS( workWin.mainView );
            timingLog.stretch = formatElapsed( Date.now()-t0 );
            console.writeln( "  Stretch: " + timingLog.stretch );
         }
         workWin.mainView.id = finalId;
         // StarX on main — unscreen if stretched, no star output
         t0 = Date.now();
         var sxtMain = new StarXTerminator;
         sxtMain.stars    = false;
         sxtMain.unscreen = !!params.enableMAS;
         if ( params.starxLargeOverlap ) sxtMain.overlap = 0.5;
         sxtMain.executeOn( workWin.mainView );
         timingLog.starMain = formatElapsed( Date.now()-t0 );
         console.writeln( "  StarX (main): " + timingLog.starMain );

      } else if ( starMode == 1 ) {
         // LINEAR STAR IMAGE: stretch main, then StarX with star output
         console.writeln( "  Star mode: Linear star image" );
         if ( params.enableMAS ) {
            t0 = Date.now();
            if      ( params.stretchTool == 1 ) runHTAutoStretch( workWin.mainView );
            else if ( params.stretchTool == 2 ) runStatisticalStretch( workWin.mainView );
            else if ( params.stretchTool == 3 ) runVeraLux( workWin.mainView );
            else if ( params.stretchTool == 4 ) runIterativeStretch( workWin.mainView );
            else                                runMAS( workWin.mainView );
            timingLog.stretch = formatElapsed( Date.now()-t0 );
            console.writeln( "  Stretch: " + timingLog.stretch );
         }
         workWin.mainView.id = finalId;
         t0 = Date.now();
         runStarX( workWin, !!params.enableMAS, true );
         timingLog.starx = formatElapsed( Date.now()-t0 );
         console.writeln( "  StarX: " + timingLog.starx );

      } else {
         // NONE: stretch then StarX with no star output, or just stretch if StarX disabled
         console.writeln( "  Star mode: None" );
         if ( params.enableMAS ) {
            t0 = Date.now();
            if      ( params.stretchTool == 1 ) runHTAutoStretch( workWin.mainView );
            else if ( params.stretchTool == 2 ) runStatisticalStretch( workWin.mainView );
            else if ( params.stretchTool == 3 ) runVeraLux( workWin.mainView );
            else if ( params.stretchTool == 4 ) runIterativeStretch( workWin.mainView );
            else                                runMAS( workWin.mainView );
            timingLog.stretch = formatElapsed( Date.now()-t0 );
            console.writeln( "  Stretch: " + timingLog.stretch );
         }
         workWin.mainView.id = finalId;
         if ( params.enableStarX ) {
            t0 = Date.now();
            runStarX( workWin, !!params.enableMAS, false );
            timingLog.starx = formatElapsed( Date.now()-t0 );
            console.writeln( "  StarX: " + timingLog.starx );
         }
      }

      if ( params.enableNoiseX ) {
         t0 = Date.now(); runNoiseX( workWin.mainView );
         timingLog.noisex = formatElapsed( Date.now()-t0 );
         console.writeln( "  NoiseX: " + timingLog.noisex );
      }

      var totalElapsed = formatElapsed( Date.now() - pipelineStart );
      workWin.show();
      workWin.zoom = -2;

      // Step timing summary
      var gradNames   = [ "GradientCorrection", "MGC", "DBE", "GraXpert", "AutoDBE" ];
      var stretchNames = [ "MAS", "HT auto", "Statistical Stretch", "VeraLux", "IterativeStretch" ];
      var starModeNames = [ "None", "Linear stars", "Stretched stars" ];
      console.writeln( "  ========================================" );
      console.writeln( "  Complete: " + finalId );
      console.writeln( "  ----------------------------------------" );
      console.writeln( "  BlurX correct:      " + ( params.enableBlurXCorrect   ? timingLog.blurxCorrect   : "Off" ) );
      console.writeln( "  Gradient removal:   " + ( params.enableGradientCorrect ? timingLog.gradient      + "  (" + gradNames[params.gradientTool] + ")" : "Off" ) );
      console.writeln( "  BackgroundNeut:     " + ( params.enableBackgroundNeutralization ? timingLog.bn : "Off" ) );
      console.writeln( "  SPCC:               " + ( params.enableSPCC           ? timingLog.spcc          : "Off" ) );
      console.writeln( "  BlurX sharpen:      " + ( params.enableBlurXSharpen   ? timingLog.blurxSharpen  : "Off" ) );
      console.writeln( "  Stretch:            " + ( params.enableMAS             ? timingLog.stretch + "  (" + stretchNames[params.stretchTool] + ")" : "Off" ) );
      if ( starMode == 2 ) {
         console.writeln( "  Star clone + StarX: " + timingLog.starClone );
         console.writeln( "  StarX (main):       " + timingLog.starMain );
      } else if ( starMode == 1 || ( starMode == 0 && params.enableStarX ) ) {
         console.writeln( "  StarX:              " + ( params.enableStarX ? timingLog.starx : "Off" ) );
      } else {
         console.writeln( "  StarX:              Off" );
      }
      console.writeln( "  NoiseX:             " + ( params.enableNoiseX         ? timingLog.noisex        : "Off" ) );
      console.writeln( "  ----------------------------------------" );
      console.writeln( "  Total:              " + totalElapsed );
      console.writeln( "  ========================================" );
      return true;

   } catch( e ) {
      var msg = e.message || e.toString() || "unknown error";
      console.criticalln( "  Error processing " + srcId + ": " + msg );
      if ( e.stack ) console.criticalln( "  Stack: " + e.stack );
      if ( params.closeIntermediates ) closeWindowById( workId );
      return false;
   }
}

// -------------------------------------------------------------------------
// Main pipeline
// -------------------------------------------------------------------------
function runPipeline() {
   var slots = [
      params.image1, params.image2, params.image3,
      params.image4, params.image5
   ];

   var images = [];
   for ( var i = 0; i < slots.length; i++ )
      if ( slots[i] != "" ) images.push( slots[i] );

   if ( images.length == 0 ) {
      (new MessageBox(
         "No images selected. Please assign at least one image.",
         SCRIPT_TITLE, StdIcon.Error, StdButton.Ok
      )).execute();
      return;
   }

   console.writeln( "" );
   console.writeln( "╔══════════════════════════════════════════════╗" );
   console.writeln( "  " + SCRIPT_TITLE + " v" + SCRIPT_VERSION );
   console.writeln( "  Processing " + images.length + " image(s)" );
   console.writeln( "╚══════════════════════════════════════════════╝" );

   var completed = 0;
   for ( var i = 0; i < images.length; i++ ) {
      if ( processImage( images[i] ) ) completed++;
   }

   console.writeln( "" );
   console.writeln( "╔══════════════════════════════════════════════╗" );
   console.writeln( "  Complete: " + completed + " of " + images.length + " images processed." );
   console.writeln( "╚══════════════════════════════════════════════╝" );
   Console.show();

   (new MessageBox(
      "Pipeline complete.\n\n" + completed + " of " + images.length +
      " image(s) processed successfully.\n\nOutput suffix: " + params.outputSuffix,
      SCRIPT_TITLE, StdIcon.Information, StdButton.Ok
   )).execute();
}

