      // Helper: update stretch tool dynamic controls
      function updateStretchControls() {
         var tool   = params.stretchTool;
         var on     = !!params.enableMAS;
         var isMAS  = ( tool == 0 ) && on;
         var isSS   = ( tool == 2 ) && on;
         var isVL   = ( tool == 3 ) && on;
         if ( masTargetCtrl )   masTargetCtrl.visible   = isMAS;
         if ( masAggCtrl )      masAggCtrl.visible      = isMAS;
         if ( masDRCCtrl )      masDRCCtrl.visible      = isMAS;
         if ( masColorSatCtrl ) masColorSatCtrl.visible = isMAS;
         if ( typeof ssTargetCtrl   !== "undefined" ) ssTargetCtrl.visible   = isSS;
         if ( typeof ssSigmaCtrl    !== "undefined" ) ssSigmaCtrl.visible    = isSS;
         if ( typeof vlTargetCtrl   !== "undefined" ) vlTargetCtrl.visible   = isVL;
         if ( typeof vlLogDCtrl     !== "undefined" ) vlLogDCtrl.visible     = isVL;
         if ( typeof vlProtectBCtrl !== "undefined" ) vlProtectBCtrl.visible = isVL;
         var isIS = ( tool == 4 ) && on;
         if ( typeof isPassesCtrl   !== "undefined" ) isPassesCtrl.visible   = isIS;
         if ( typeof isTargetBgCtrl !== "undefined" ) isTargetBgCtrl.visible = isIS;
         if ( typeof isSpRangeCtrl  !== "undefined" ) isSpRangeCtrl.visible  = isIS;
         if ( typeof isShadowsCtrl  !== "undefined" ) isShadowsCtrl.visible  = isIS;
      }

