      var previewCombo = new ComboBox( self );
      previewCombo.editEnabled = false;
      previewCombo.toolTip = "Select a preview from the active image to use as background reference\n" +
                             "for BackgroundNeutralization, SPCC, and MAS background measurement.\n" +
                             "Define a preview over a clean background region before running PCP.";

      function refreshPreviewCombo( imageId ) {
         var saved = previewCombo.numberOfItems > 0 ? previewCombo.itemText( previewCombo.currentItem ) : "None";
         while ( previewCombo.numberOfItems > 0 ) previewCombo.removeItem( 0 );
         previewCombo.addItem( "None" );
         if ( imageId && imageId != "" ) {
            var win = windowById( imageId );
            if ( win ) {
               var previews = win.previews;
               for ( var pi = 0; pi < previews.length; pi++ )
                  previewCombo.addItem( previews[pi].id );
            }
         }
         params.roiPreviewId = "";
         for ( var pj = 0; pj < previewCombo.numberOfItems; pj++ )
            if ( previewCombo.itemText(pj) == saved ) {
               previewCombo.currentItem = pj;
               if ( saved != "None" ) params.roiPreviewId = saved;
               break;
            }
         previewCombo.enabled = ( previewCombo.numberOfItems > 1 );
      }
      previewCombo.onItemSelected = function(i) {
         var sel = previewCombo.itemText(i);
         params.roiPreviewId = ( sel == "None" ) ? "" : sel;
      };

