      var onToggleSection = function( bar, beginToggle ) {
         if ( beginToggle ) {}
         else {
            self.adjustToContents();
            self.setVariableSize();
         }
      };

      function makeContainer( controls ) {
         var c = new Control( self );
         c.sizer = new VerticalSizer;
         c.sizer.margin  = 6;
         c.sizer.spacing = 4;
         for ( var ci = 0; ci < controls.length; ci++ ) {
            if ( controls[ci] === null )
               c.sizer.addSpacing( 2 );
            else
               c.sizer.add( controls[ci] );
         }
         return c;
      }

      function makeBar( container, title ) {
         var bar = new SectionBar( self, title );
         bar.setSection( container );
         bar.onToggleSection = onToggleSection;
         return bar;
      }

