      var cont5 = makeContainer( [ masCheck, stretchToolRow, masTargetCtrl, masAggCtrl, masDRCCtrl, masColorSatCtrl, ssTargetCtrl, ssSigmaCtrl, vlTargetCtrl, vlLogDCtrl, vlProtectBCtrl ] );
