function main() {
   printPDFSplash();
   Console.writeln( "" );
   Console.writeln( "+================================================+" );
   Console.writeln( "|         Process Container Plus  v" + SCRIPT_VERSION + "             |" );
   Console.writeln( "|   Linear preprocessing pipeline                |" );
   Console.writeln( "+================================================+" );

   loadSettings();

   if ( ImageWindow.windows.length == 0 ) {
      (new MessageBox(
         "No images are open. Please open your linear images first.",
         SCRIPT_TITLE, StdIcon.Error, StdButton.Ok
      )).execute();
      return;
   }

   var dlg = new PCPDialog();
   dlg.execute();
}

main();
